package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        // Create CSVFormat instance with nullString = null using reflection since constructor is private
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set private field nullString to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, null);

        assertFalse(format.isNullStringSet());
    }

    @Test
    public void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, "NULL");

        assertTrue(format.isNullStringSet());
    }
}
